VARIABLES state, phase

(* Initial state: all participants are in INIT state and phase is PREPARE *)
Init == 
  /\ state = [p \in 1..N |-> "INIT"]
  /\ phase = "PREPARE"

(* Transition relation *)
Next == 
  \E p \in 1..N :
    /\ phase = "PREPARE"
    /\ state[p] = "INIT"
    /\ state' = [state EXCEPT ![p] = "VOTED"]
  \/ \E p \in 1..N :
    /\ phase = "PREPARE"
    /\ state[p] = "VOTED"
    /\ state' = [state EXCEPT ![p] = "COMMITTED"]
  \/ \E p \in 1..N :
    /\ phase = "PREPARE"
    /\ state[p] = "VOTED"
    /\ state' = [state EXCEPT ![p] = "ABORTED"]
  \/ phase = "COMMIT" /\ phase' = phase
  \/ phase = "ABORT" /\ phase' = phase

(* Invariant: if any participant is ABORTED, then phase is ABORT *)
TypeOK == 
  /\ state \in [1..N -> {"INIT", "VOTED", "COMMITTED", "ABORTED"}]
  /\ phase \in {"PREPARE", "COMMIT", "ABORT"}

Spec == Init /\ [][Next]_<<state, phase>>

